import {
  GameManifest,
  GameType,
  NormalizedSubmitBody,
  RawResult,
} from "./contract/types";
import { LaunchContext } from "./protocol/protocol";

import { convertQuiz } from "./converters/quiz";

export interface NormalizationReport {
  body: NormalizedSubmitBody;
  warnings: string[];
}

export function normalizeResult(
  gameType: GameType,
  raw: unknown, // RawResult or any
  context?: LaunchContext,
  _manifest?: GameManifest
): NormalizationReport {
  const warnings: string[] = [];
  const rawObj = raw && typeof raw === "object" ? (raw as RawResult) : {};

  // 1. Base fields extraction
  let durationMs = 0;
  if (typeof rawObj.durationMs === "number") durationMs = rawObj.durationMs;
  else if (typeof rawObj.timeTaken === "number")
    durationMs = rawObj.timeTaken; // Compat
  else warnings.push("Missing durationMs");

  let score = 0;
  if (typeof rawObj.score === "number") score = rawObj.score;
  else warnings.push("Missing score");

  let attemptId = "";
  if (typeof rawObj.attemptId === "string" && rawObj.attemptId) {
    attemptId = rawObj.attemptId;
  } else if (context?.sessionId) {
    // Generate distinct attemptId? Or just use sessionId if 1 attempt/session?
    // Usually session = 1 attempt.
    attemptId = context.sessionId;
  } else {
    // Fallback?
    attemptId = "manual_" + Date.now();
    warnings.push("Missing attemptId, generated fallback");
  }

  // 2. Type-specific conversion
  let partial: Partial<NormalizedSubmitBody> = {};

  if (gameType === "quiz") {
    const res = convertQuiz(rawObj);
    partial = res.fields;
    warnings.push(...res.warnings);
  }
  // TODO: Add drag_drop, trace, etc.

  // 3. Merge & Defaults
  const completion = isFiniteNumber(partial.completion)
    ? partial.completion!
    : isFiniteNumber(rawObj.completion)
    ? rawObj.completion!
    : 1;
  const accuracy = isFiniteNumber(partial.accuracy)
    ? partial.accuracy!
    : isFiniteNumber(rawObj.accuracy)
    ? rawObj.accuracy!
    : 0;

  // Clamp 0..1
  const finalCompletion = Math.min(1, Math.max(0, completion));
  const finalAccuracy = Math.min(1, Math.max(0, accuracy));

  // 4. Construct Payload (keep raw as payload for now, or specific subset?)
  // Doc says: result_payload
  const resultPayload =
    rawObj.resultPayload && typeof rawObj.resultPayload === "object"
      ? (rawObj.resultPayload as Record<string, unknown>)
      : rawObj; // Fallback: extraction of everything as payload

  const body: NormalizedSubmitBody = {
    attemptId,
    durationMs,
    score,
    completion: finalCompletion,
    accuracy: finalAccuracy,
    resultPayload: resultPayload as Record<string, unknown>,
  };

  return { body, warnings };
}

function isFiniteNumber(v: unknown): v is number {
  return typeof v === "number" && Number.isFinite(v);
}
