import { MessageType, MsgEnvelope } from "../protocol"; // Imported from index.ts inside protocol folder
import type { LaunchContext } from "../contract/types";
import { LaunchContextSchema, GameResultSchema } from "../contract/schemas";
import { ErrorCode, SdkError } from "../contract/errors";

// Mock Context for standalone development (no Hub)
const MOCK_CONTEXT: LaunchContext = {
  sessionId: "dev-session-local",
  gameId: "local-dev-game",
  mode: "dev",
  locale: "vi",
  difficulty: "medium",
  player: { name: "Developer", id: "dev-001" },
  soundEnabled: true,
};

export interface GameBridge {
  context: LaunchContext;
  send: (type: string, payload?: any) => void;
  on: (type: string, callback: (payload: any) => void) => void;
}

/**
 * Connect to Hub parent window. Returns Promise containing LaunchContext when connection succeeds.
 *
 * The Game will send HELLO messages every 200ms until the Hub responds with INIT.
 * This prevents race conditions where the Hub sends commands before the Game is ready.
 *
 * If no Hub responds within the timeout period, automatically switches to DEV/MOCK mode
 * for standalone development.
 *
 * @param targetOrigin - Target origin for postMessage (default: "*")
 * @param timeoutMs - Connection timeout in milliseconds (default: 2000)
 * @returns Promise<GameBridge> - Resolves when handshake completes or timeout occurs
 */
export function connectToHub(
  targetOrigin = "*",
  timeoutMs = 2000
): Promise<GameBridge> {
  return new Promise((resolve, reject) => {
    let handshakeInterval: any = null;
    let isConnected = false;
    const listeners = new Map<string, (payload: any) => void>();

    // Send message wrapper (works for both real and mock mode)
    const sendMessage = (type: string, payload?: any) => {
      // [Validation Output] - Validate Game Result
      if (type === MessageType.COMPLETE && payload) {
        const parse = GameResultSchema.safeParse(payload);
        if (!parse.success) {
          console.warn("⚠️ Game đang gửi kết quả không chuẩn:", parse.error);
          return; // Block invalid result
        }
        // Use sanitized data
        payload = parse.data;
      }

      if (isConnected) {
        // Production: Send to real Hub
        const envelope: MsgEnvelope = {
          source: "game",
          type,
          payload,
          sdkVersion: "1.0.0",
          sessionId: "pending",
          gameId: "unknown",
        };

        window.parent.postMessage(envelope, targetOrigin);
      } else {
        // Dev Mode: Log to console for debugging
        console.debug(
          `%c[MockBridge 📤] ${type}`,
          "color: green; font-weight: bold",
          payload
        );
      }
    };

    // Listen for responses from Hub
    const messageHandler = (event: MessageEvent) => {
      const data = event.data as MsgEnvelope;

      // Security check
      if (data?.source !== "hub") return;

      // Handle Handshake: Received INIT from Hub
      if (data.type === MessageType.INIT && !isConnected) {
        try {
          // [Validation Input] - Validate Launch Context
          const validContext = LaunchContextSchema.parse(data.payload);

          console.log("✅ [GameSDK] Connected to Real Hub.");

          // Stop spamming HELLO
          clearInterval(handshakeInterval);
          isConnected = true;

          // Create Bridge object for production mode
          const bridge: GameBridge = {
            context: validContext,
            send: sendMessage,
            on: (type, cb) => {
              // Register event listener for Hub commands
              window.addEventListener("message", (e) => {
                const msg = e.data as MsgEnvelope;
                if (msg.source === "hub" && msg.type === type) {
                  cb(msg.payload);
                }
              });
            },
          };

          resolve(bridge);
        } catch (validationError) {
          console.error("❌ Invalid Launch Context:", validationError);

          // Reply error to Hub
          window.parent.postMessage(
            {
              type: MessageType.ERROR,
              source: "game",
              payload: {
                code: ErrorCode.SYS_INVALID_CONTEXT,
                message: "Launch Context validation failed",
                details: validationError,
              },
            },
            targetOrigin
          );

          // Reject/Fail - Optional: we might not reject to avoid unhandled rejection crash,
          // but the user plan says strict gatekeeper.
          // If we don't resolve, game hangs. If we reject without catching, uncaught promise.
          // User sample code says: reject(new SdkError(...));
          // I will follow sample.
          reject(
            new SdkError(
              ErrorCode.SYS_INVALID_CONTEXT,
              "Invalid Context",
              validationError
            )
          );
        }
      }
    };

    window.addEventListener("message", messageHandler);

    // Start Handshake Loop
    // Send HELLO every 200ms until Hub responds
    console.log("[GameSDK] Waiting for Hub...");
    handshakeInterval = setInterval(() => {
      sendMessage(MessageType.HELLO);
    }, 200);

    // TIMEOUT LOGIC: Switch to Dev/Mock Mode
    // After timeout, if no Hub responds, use mock context for standalone development
    setTimeout(() => {
      if (!isConnected) {
        clearInterval(handshakeInterval);
        window.removeEventListener("message", messageHandler);

        console.warn(
          "⚠️ [GameSDK] Connection timed out. Switching to DEV/MOCK mode."
        );

        // Create Mock Bridge for standalone development
        const mockBridge: GameBridge = {
          context: MOCK_CONTEXT,
          send: (type, payload) => {
            // Simple mock send
            console.log(
              `%c[MockBridge 📤] ${type}`,
              "color: green; font-weight: bold",
              payload
            );
          },
          on: (type, cb) => {
            console.log(
              `%c[MockBridge 👂] Registered listener: ${type}`,
              "color: blue"
            );
            listeners.set(type, cb);
          },
        };

        resolve(mockBridge);
      }
    }, timeoutMs);
  });
}
