import { z } from "zod";

/**
 * Schema cho Context khởi tạo từ Hub.
 * Sử dụng .passthrough() để chấp nhận các trường mới từ Backend trong tương lai
 * mà không làm crash game cũ.
 */
export const LaunchContextSchema = z
  .object({
    // Bắt buộc phải có
    sessionId: z.string().min(1),
    gameId: z.string().min(1),

    // Optional Technical Fields
    sdkVersion: z.string().optional(),
    lessonId: z.string().optional(),
    gameVersion: z.string().optional(),

    // Có default value (Phòng trường hợp BE quên gửi)
    mode: z.enum(["production", "dev", "review"]).default("production"),
    locale: z.string().default("vi"),
    difficulty: z.enum(["easy", "medium", "hard"]).default("medium"),

    // Optional Objects
    player: z
      .object({
        id: z.string().optional(),
        name: z.string().default("Student"),
        avatar: z.string().optional(),
      })
      .optional()
      .default({}), // Default object rỗng để tránh lỗi null access

    // Settings
    soundEnabled: z.boolean().default(true),
  })
  .passthrough(); // <--- CHÌA KHÓA CỦA SCALABILITY

/**
 * Schema cho Kết quả Game gửi lên.
 * Validate chặt chẽ để không làm bẩn Database.
 */
export const GameResultSchema = z.object({
  score: z.number().min(0, "Score cannot be negative"),
  completion: z.number().min(0).max(1, "Completion must be 0-1"),
  accuracy: z.number().min(0).max(1).optional(),

  // Metadata mở rộng (cho phép gửi object tùy ý nhưng phải an toàn)
  details: z.record(z.unknown()).optional(),

  timestamp: z.number().default(() => Date.now()),
});
